#include <iostream>

// Recursive function that returns the n‑th Fibonacci number.
// fib(0) = 0, fib(1) = 1, fib(n) = fib(n-1) + fib(n-2) for n > 1.
long long fib(int n)
{
    if (n <= 0)               // handles negative or zero input
        return 0;
    if (n == 1)
        return 1;

    return fib(n - 1) + fib(n - 2);
}

int main()
{
    std::cout << "Enter the index n (non‑negative integer): ";
    int n;
    std::cin >> n;

    // Guard against negative input
    if (n < 0) {
        std::cerr << "Error: n must be non‑negative.\n";
        return 1;
    }

    long long result = fib(n);
    std::cout << "Fibonacci(" << n << ") = " << result << '\n';
    return 0;
}
```

